package pcd.startingPoool.model.game;

import java.util.Objects;

public final class Boundary {
    private final double x0;
    private final double y0;
    private final double x1;
    private final double y1;

    public Boundary(double x0, double y0, double x1, double y1) {
        this.x0 = x0;
        this.y0 = y0;
        this.x1 = x1;
        this.y1 = y1;
    }

    public double x0() {
        return x0;
    }

    public double y0() {
        return y0;
    }

    public double x1() {
        return x1;
    }

    public double y1() {
        return y1;
    }

    @Override
    public boolean equals(Object obj) {
        if (this == obj) {
            return true;
        }
        if (!(obj instanceof Boundary other)) {
            return false;
        }
        return Double.compare(x0, other.x0) == 0
                && Double.compare(y0, other.y0) == 0
                && Double.compare(x1, other.x1) == 0
                && Double.compare(y1, other.y1) == 0;
    }

    @Override
    public int hashCode() {
        return Objects.hash(x0, y0, x1, y1);
    }

    @Override
    public String toString() {
        return "Boundary[x0=" + x0 + ", y0=" + y0 + ", x1=" + x1 + ", y1=" + y1 + "]";
    }
}

